if (! function_exists('text_adventure_game')) {
    function text_adventure_game($state, $command)
    {
        // Initialize game state
        if (trim($state ?? '') === '' || trim($state ?? '') === 'new') {
            $game = [
                'player' => [
                    'room' => 'entrance_hall',
                    'inventory' => [],
                ],
                'rooms' => [
                    'entrance_hall' => [
                        'name' => 'Entrance Hall',
                        'description' => 'A grand entrance hall with marble floors and tall pillars. Dust motes dance in shafts of light from high windows. Exits lead north, east, and west.',
                        'exits' => ['north' => 'library', 'east' => 'kitchen', 'west' => 'garden'],
                        'items' => ['torch'],
                        'description_detailed' => 'Cobwebs stretch between the pillars. An old torch rests in a bracket on the wall. The main doors are sealed behind you.',
                    ],
                    'library' => [
                        'name' => 'Library',
                        'description' => 'A vast library filled floor-to-ceiling with dusty tomes. A large oak table sits in the center. Exits lead south and east.',
                        'exits' => ['south' => 'entrance_hall', 'east' => 'tower'],
                        'items' => ['ancient_book'],
                        'description_detailed' => 'Books on alchemy, history, and arcane arts line the shelves. One book lies open on the table — it seems important.',
                    ],
                    'kitchen' => [
                        'name' => 'Kitchen',
                        'description' => 'A warm kitchen with a great stone hearth. Pots and pans hang from hooks. Exits lead west and north.',
                        'exits' => ['west' => 'entrance_hall', 'north' => 'armory'],
                        'items' => ['silver_spoon'],
                        'description_detailed' => 'A fire crackles in the hearth. A silver spoon gleams on the counter. The pantry door is slightly ajar.',
                    ],
                    'armory' => [
                        'name' => 'Armory',
                        'description' => 'A cold stone armory. Weapon racks line the walls, most of them empty. Exits lead south only.',
                        'exits' => ['south' => 'kitchen'],
                        'items' => ['sword'],          // BUG FIXED: removed 'rusty_key' - now only found via mirror puzzle
                        'description_detailed' => 'This chamber has been picked clean except for a few remnants. A sword leans against the wall, ready for battle.',
                        'require_item' => null,
                    ],
                    'garden' => [
                        'name' => 'Overgrown Garden',
                        'description' => 'A wild, overgrown garden with crumbling stone pathways. A fountain gurgles weakly at the center. Exits lead east.',
                        'exits' => ['east' => 'entrance_hall'],
                        'items' => ['magic_mirror'],
                        'description_detailed' => 'Thorny vines have overtaken the rose bushes. In the fountain\'s basin, something glitters — a small hand mirror with an ornate frame.',
                    ],
                    'tower' => [
                        'name' => 'Tall Tower',
                        'description' => 'A spiral staircase winds up into a circular room with tall narrow windows. Exits lead west and down.',
                        'exits' => ['west' => 'library', 'down' => 'dungeon'],
                        'items' => [],
                        'description_detailed' => 'Through the windows you can see the whole kingdom. A trapdoor in the floor leads down into darkness.',
                        'require_item' => 'torch',
                        'require_item_msg' => 'It\'s too dark to go down there without a light source!',
                    ],
                    'dungeon' => [
                        'name' => 'Dark Dungeon',
                        'description' => 'A damp, dark dungeon lit by your torch. Cells line the corridor. Exits lead up and east.',
                        'exits' => ['up' => 'tower', 'east' => 'throne_room'],
                        'items' => ['shield'],
                        'description_detailed' => 'The air is thick with the smell of mildew. A rusty shield rests against a cell door. Faint light comes from the east.',
                        'require_item' => 'rusty_key',
                        'require_item_msg' => 'The dungeon door is locked! You need a rusty key to enter.',
                    ],
                    'throne_room' => [
                        'name' => 'Throne Room',
                        'description' => 'A magnificent throne room with a red carpet leading to an ornate throne. A fearsome Guardian stands before it! Exits lead west.',
                        'exits' => ['west' => 'dungeon'],
                        'items' => ['crown'],
                        'description_detailed' => 'The Guardian is a massive suit of animated armor wielding a great axe. Behind it, on a velvet cushion, sits a gleaming crown.',
                        'guardian_defeated' => false,
                    ],
                ],
                'flags' => [
                    'torch_lit' => false,
                    'guardian_defeated' => false,
                    'game_won' => false,
                    'tower_trapdoor_open' => false,
                    'book_read' => false,
                    'mirror_used' => false,
                ],
                'messages' => [],
            ];
            $state_json = json_encode($game);
            // Return initial look
            return json_encode([
                'state' => $state_json,
                'output' => "=== THE CROWN OF KINGS ===\n\n" .
                            "You stand in the " . $game['rooms'][$game['player']['room']]['name'] . ".\n" .
                            $game['rooms'][$game['player']['room']]['description'] . "\n\n" .
                            "Items here: " . (empty($game['rooms'][$game['player']['room']]['items']) ? 'none' : implode(', ', $game['rooms'][$game['player']['room']]['items'])) . "\n\n" .
                            "Type 'help' for commands.\n" .
                            "Your quest: Find the Crown of Kings and claim the throne!"
            ]);
        }

        $game = json_decode($state, true);
        if ($game === null) {
            return json_encode(['state' => $state, 'output' => 'Error: Invalid game state.']);
        }

        $cmd = trim($command);
        $output = '';
        $room = &$game['rooms'][$game['player']['room']];
        $player = &$game['player'];
        $flags = &$game['flags'];

        // Parse command
        $parts = preg_split('/\s+/', $cmd, 2);
        $verb = strtolower($parts[0] ?? '');
        $noun = strtolower($parts[1] ?? '');

        // Normalize some inputs
        $direction_map = ['n' => 'north', 's' => 'south', 'e' => 'east', 'w' => 'west', 'u' => 'up', 'd' => 'down'];

        switch ($verb) {
            case 'help':
                $output = "=== COMMANDS ===\n\n" .
                          "look          - Describe the current room\n" .
                          "go [dir]      - Move in a direction (north/south/east/west/up/down)\n" .
                          "take [item]   - Pick up an item\n" .
                          "drop [item]   - Drop an item from inventory\n" .
                          "inventory / i - List carried items\n" .
                          "examine [item] - Look at something in detail\n" .
                          "use [item]    - Use an item (try: use torch, use mirror, use book)\n" .
                          "help          - Show this help\n\n" .
                          "=== QUEST ===\n" .
                          "Find the Crown of Kings and claim it as your own!";
                break;

            case 'look':
                $output = "=== " . $room['name'] . " ===\n";
                $output .= $room['description'] . "\n\n";
                
                // Check for special room conditions
                if ($room['name'] === 'Throne Room' && !$flags['guardian_defeated']) {
                    $output .= "A fearsome Guardian bars your way to the Crown!\n";
                }
                
                // Describe items
                if (!empty($room['items'])) {
                    $output .= "You can see: " . implode(', ', $room['items']) . "\n";
                }
                
                // Describe exits
                $exit_names = [];
                foreach ($room['exits'] as $dir => $target) {
                    $exit_names[] = $dir;
                }
                $output .= "Exits: " . implode(', ', $exit_names);
                
                if (!empty($room['description_detailed'])) {
                    $output .= "\n\n" . $room['description_detailed'];
                }
                break;

            case 'go':
            case 'move':
                // Handle shorthand
                if (isset($direction_map[$noun])) {
                    $noun = $direction_map[$noun];
                }
                
                if (!isset($room['exits'][$noun])) {
                    $output = "You can't go that way.";
                    break;
                }
                
                // Check requirements for entering the target room
                $target_room_id = $room['exits'][$noun];
                $target_room = &$game['rooms'][$target_room_id];
                
                if (isset($target_room['require_item']) && $target_room['require_item'] !== null) {
                    $required = $target_room['require_item'];
                    if (!in_array($required, $player['inventory'])) {
                        $msg = $target_room['require_item_msg'] ?? "You need $required to enter here.";
                        $output = $msg;
                        break;
                    }
                }
                
                // Special case: tower->dungeon needs torch lit
                if ($target_room_id === 'dungeon' && $room['name'] === 'Tall Tower' && !$flags['torch_lit']) {
                    $output = "It's pitch black down there! You need to light a torch first.";
                    break;
                }
                
                // Move player
                $game['player']['room'] = $target_room_id;
                $room = &$game['rooms'][$game['player']['room']];
                
                $output = "You go $noun.\n\n";
                $output .= "=== " . $room['name'] . " ===\n";
                $output .= $room['description'] . "\n";
                
                if (!empty($room['items'])) {
                    $output .= "\nItems here: " . implode(', ', $room['items']);
                }
                
                if (!empty($room['description_detailed'])) {
                    $output .= "\n" . $room['description_detailed'];
                }
                break;

            case 'take':
            case 'get':
                if (empty($noun)) {
                    $output = "Take what?";
                    break;
                }
                
                // Find the item (case-insensitive)
                $found_item = null;
                foreach ($room['items'] as $idx => $item) {
                    if (strtolower($item) === $noun) {
                        $found_item = $item;
                        $index = $idx;
                        break;
                    }
                }
                
                if ($found_item === null) {
                    $output = "There's no $noun here.";
                    break;
                }
                
                // Remove from room, add to inventory
                array_splice($room['items'], $index, 1);
                $player['inventory'][] = $found_item;
                $output = "You take the $found_item.";
                break;

            case 'drop':
                if (empty($noun)) {
                    $output = "Drop what?";
                    break;
                }
                
                $found_item = null;
                foreach ($player['inventory'] as $idx => $item) {
                    if (strtolower($item) === $noun) {
                        $found_item = $item;
                        $index = $idx;
                        break;
                    }
                }
                
                if ($found_item === null) {
                    $output = "You don't have $noun.";
                    break;
                }
                
                array_splice($player['inventory'], $index, 1);
                $room['items'][] = $found_item;
                $output = "You drop the $found_item.";
                break;

            case 'inventory':
            case 'i':
                if (empty($player['inventory'])) {
                    $output = "You are carrying nothing.";
                } else {
                    $output = "You are carrying:\n  " . implode("\n  ", $player['inventory']);
                }
                break;

            case 'examine':
            case 'exam':
            case 'x':
                if (empty($noun)) {
                    $output = "Examine what?";
                    break;
                }
                
                // Check inventory and room
                $all_items = array_merge($player['inventory'], $room['items']);
                $found = false;
                foreach ($all_items as $item) {
                    if (strtolower($item) === $noun) {
                        $found = true;
                        $item_name = $item;
                        break;
                    }
                }
                
                if (!$found) {
                    $output = "You don't see $noun here.";
                    break;
                }
                
                switch ($item_name) {
                    case 'torch':
                        $output = "A wooden torch wrapped in oiled cloth. It can be lit if you have a way to strike a flame. (Try: use torch)";
                        break;
                    case 'ancient_book':
                        $output = "An ancient leather-bound book written in a forgotten tongue. As you flip through it, a diagram catches your eye — it shows a mirror reflecting sunlight to reveal a hidden compartment. Something about 'in the garden...'";
                        $flags['book_read'] = true;
                        break;
                    case 'magic_mirror':
                        $output = "A beautiful hand mirror with an intricate silver frame. The glass seems to shimmer with an inner light. The book mentioned something about using this in the garden...";
                        break;
                    case 'rusty_key':
                        $output = "A large iron key, heavy and covered in rust. It looks like it belongs to a dungeon door.";
                        break;
                    case 'silver_spoon':
                        $output = "A finely crafted silver spoon. Not particularly useful, but it might be valuable.";
                        break;
                    case 'sword':
                        $output = "A well-balanced steel longsword. The blade still holds an edge. This could be useful against the Guardian!";
                        break;
                    case 'shield':
                        $output = "A sturdy iron shield with the royal crest still visible. It could provide protection in battle.";
                        break;
                    case 'crown':
                        $output = "The legendary Crown of Kings! Wrought of gold and studded with gems, it radiates power. This is what you came for!";
                        break;
                    default:
                        $output = "You see nothing special about the $item_name.";
                }
                break;

            case 'use':
                if (empty($noun)) {
                    $output = "Use what?";
                    break;
                }
                
                if (!in_array($noun, $player['inventory'])) {
                    $output = "You don't have $noun to use.";
                    break;
                }
                
                switch ($noun) {
                    case 'torch':
                        if ($flags['torch_lit']) {
                            $output = "The torch is already lit.";
                        } else {
                            // Need to be in a room where you can light it
                            if ($game['player']['room'] === 'kitchen') {
                                $flags['torch_lit'] = true;
                                $output = "You light the torch from the hearth fire. The room glows with warm light!";
                            } else {
                                $output = "You have nothing to light the torch with. Maybe try the kitchen hearth...";
                            }
                        }
                        break;

                    case 'magic_mirror':
                        if ($game['player']['room'] === 'garden') {
                            if ($flags['book_read']) {
                                $output = "Holding the magic mirror up, you catch the sunlight and angle it just as the book described. A beam of light hits the fountain, revealing a hidden panel! Inside is a rusty key!";
                                if (!in_array('rusty_key', $game['rooms']['garden']['items'])) {
                                    $game['rooms']['garden']['items'][] = 'rusty_key';
                                }
                                $flags['mirror_used'] = true;
                            } else {
                                $output = "You look at yourself in the mirror. It's very reflective, but you're not sure what to do with it. Maybe some book could tell you...";
                            }
                        } else {
                            $output = "The mirror glints in the light, but nothing happens here. Maybe it needs to be in the garden?";
                        }
                        break;

                    case 'ancient_book':
                        $output = "You flip through the ancient book. The pages are brittle but readable. It speaks of a mirror that reveals hidden things when used in sunlight...";
                        $flags['book_read'] = true;
                        break;

                    case 'sword':
                        if ($game['player']['room'] === 'throne_room' && !$flags['guardian_defeated']) {
                            $flags['guardian_defeated'] = true;
                            $game['rooms']['throne_room']['guardian_defeated'] = true;
                            $output = "You raise the sword and face the Guardian! Steel clashes against steel as you exchange blows. With a final, powerful strike, you shatter the Guardian's axe and it crumbles to pieces! The path to the Crown is clear!";
                        } else if ($game['player']['room'] === 'throne_room' && $flags['guardian_defeated']) {
                            $output = "The Guardian has already been defeated. The Crown awaits!";
                        } else {
                            $output = "You swing the sword through the air. It feels powerful, but there's nothing to fight here.";
                        }
                        break;

                    case 'shield':
                        if ($flags['guardian_defeated']) {
                            $output = "The shield is no longer needed. The Guardian is already defeated.";
                        } else {
                            $output = "You strap the shield to your arm. It feels sturdy and protective.";
                        }
                        break;

                    case 'crown':
                        if ($flags['guardian_defeated'] && $game['player']['room'] === 'throne_room') {
                            $flags['game_won'] = true;
                            $output = "You lift the Crown of Kings and place it upon your head. A warm glow surrounds you as the kingdom recognizes its true ruler. YOU HAVE WON! Long may you reign!";
                        } else if ($game['player']['room'] === 'throne_room' && !$flags['guardian_defeated']) {
                            $output = "The Guardian stands between you and the Crown! You must defeat it first.";
                        } else if ($game['player']['room'] !== 'throne_room') {
                            $output = "You're not in the Throne Room. The crown isn't here.";
                        } else {
                            $output = "You take the crown... what do you do with it?";
                        }
                        break;

                    default:
                        $output = "You can't use the $noun.";
                }
                break;

            case 'read':
                if (str_contains($cmd, 'book') || str_contains($cmd, 'note') || str_contains($cmd, 'scroll')) {
                    // Check if they have the book
                    if (in_array('ancient_book', $player['inventory'])) {
                        $flags['book_read'] = true;
                        $output = "You read the ancient book. It describes how a magic mirror can reveal hidden things when used in the sunlight of the garden...";
                    } else {
                        $output = "You don't have anything to read.";
                    }
                } else {
                    $output = "Read what?";
                }
                break;

            default:
                $output = "I don't understand '$cmd'. Type 'help' for a list of commands.";
        }

        // Check for win condition
        if ($flags['game_won']) {
            $output .= "\n\n=== VICTORY! ===";
        }

        return json_encode([
            'state' => json_encode($game),
            'output' => $output,
        ]);
    }
}
